(()=>{var e=document.getElementsByTagName("html")[0],t=localStorage.getItem("theme");t?(e.setAttribute("data-user-color-scheme",t),e.classList.add(`${t}-theme`)):window.matchMedia("(prefers-color-scheme: dark)").matches?(e.setAttribute("data-user-color-scheme","dark"),e.classList.add("dark-theme")):(e.setAttribute("data-user-color-scheme","light"),e.classList.add("light-theme"));})();
